 31→// --- COMPOSANTS DE STYLE ---
 32→const NoiseTexture = () => (
 33→  <svg className="fixed inset-0 w-full h-full pointer-events-none opacity-[0.015] z-50" style={{ mixBlendMode: 'overlay' }}>
 34→    <filter id="noise"><feTurbulence type="fractalNoise" baseFrequency="0.8" numOctaves="4" stitchTiles="stitch"/></filter>
 35→    <rect width="100%" height="100%" filter="url(#noise)"/>
 36→  </svg>
 37→);
 38→
 39→const GradientOrbs = () => (
 40→  <div className="fixed inset-0 overflow-hidden pointer-events-none">
 41→    <div className="absolute -top-40 -right-40 w-[600px] h-[600px] rounded-full bg-emerald-500/20 blur-3xl animate-pulse" />
 42→    <div className="absolute top-1/2 -left-40 w-[500px] h-[500px] rounded-full bg-blue-500/15 blur-3xl animate-pulse" />
 43→  </div>
 44→);
