 46→// --- COMPOSANT PRINCIPAL ---
 47→export default function App() {
 48→  const [url, setUrl] = useState('');
 49→  const [isAnalyzing, setIsAnalyzing] = useState(false);
 50→  const [analysisComplete, setAnalysisComplete] = useState(false);
 51→  const [activeTab, setActiveTab] = useState('overview');
 52→  const resultsRef = useRef<HTMLDivElement>(null);
 53→
 54→  const runAnalysis = () => {
 55→    if (!url) return;
 56→    setIsAnalyzing(true);
 57→    // Simulation d'analyse
 58→    setTimeout(() => {
 59→      setIsAnalyzing(false);
 60→      setAnalysisComplete(true);
 61→    }, 3000);
 62→  };
 63→
 64→  return (
 65→    <div className="min-h-screen bg-[#0a0a0f] text-white selection:bg-emerald-500/30 font-sans">
 66→      <NoiseTexture />
 67→      <GradientOrbs />
 68→
 69→      {/* Header */}
 70→      <header className="relative z-40 border-b border-white/5 backdrop-blur-md bg-[#0a0a0f]/50 sticky top-0">
 71→        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
 72→          <div className="flex items-center gap-3">
 73→            <div className="bg-emerald-500 p-2 rounded-xl">
 74→              <Sparkles className="w-6 h-6 text-white" />
 75→            </div>
 76→            <h1 className="text-xl font-bold">CitedBy<span className="text-emerald-400">.ai</span></h1>
 77→          </div>
 78→          <button className="bg-white/5 border border-white/10 px-5 py-2 rounded-full text-sm">Connexion</button>
 79→        </div>
 80→      </header>
 81→
 82→      <main className="relative z-10 pt-20 pb-24 px-6">
 83→        {/* Barre de recherche (L'entrée du SaaS) */}
 84→        {!analysisComplete && (
 85→          <div className="max-w-4xl mx-auto text-center">
 86→            <h2 className="text-6xl font-bold mb-6">Faites-vous <span className="text-emerald-400">citer</span> par les IA</h2>
 87→            <p className="text-xl text-white/50 mb-10">Optimisez votre site pour ChatGPT, Claude et Perplexity.</p>
 88→            
 89→            <div className="relative max-w-2xl mx-auto group">
 90→              <div className="flex bg-white/5 border border-white/10 rounded-2xl p-2">
 91→                <input 
 92→                  className="flex-1 bg-transparent px-4 py-4 outline-none text-lg" 
 93→                  placeholder="https://votre-site.com" 
 94→                  value={url}
 95→                  onChange={(e) => setUrl(e.target.value)}
 96→                />
 97→                <button 
 98→                  onClick={runAnalysis}
 99→                  disabled={isAnalyzing}
100→                  className="bg-emerald-500 hover:bg-emerald-400 text-black px-8 py-4 rounded-xl font-bold transition-all"
101→                >
102→                  {isAnalyzing ? <Loader2 className="animate-spin" /> : "Analyser"}
103→                </button>
104→              </div>
105→            </div>
106→          </div>
107→        )}
108→
109→        {/* L'interface Tableau de Bord (Une fois l'analyse faite) */}
110→        {analysisComplete && (
111→          <div ref={resultsRef} className="max-w-6xl mx-auto animate-in fade-in slide-in-from-bottom-4 duration-1000">
112→            <div className="flex items-center justify-between mb-8 p-6 bg-white/5 border border-white/10 rounded-2xl">
113→              <div className="flex items-center gap-4">
114→                <Globe className="w-6 h-6 text-emerald-400" />
115→                <div>
116→                  <p className="text-white/40 text-sm">Analyse de</p>
117→                  <p className="text-white font-medium">{url}</p>
118→                </div>
119→              </div>
120→              <button onClick={() => setAnalysisComplete(false)} className="text-emerald-400 text-sm flex items-center gap-2">
121→                <RefreshCw className="w-4 h-4" /> Nouvelle analyse
122→              </button>
123→            </div>
124→
125→            {/* Onglets du SaaS */}
126→            <div className="flex gap-4 mb-8">
127→              {['overview', 'recommendations', 'ai-preview'].map(t => (
128→                <button 
129→                  key={t} 
130→                  onClick={() => setActiveTab(t)}
131→                  className={`px-6 py-2 rounded-full text-sm transition-all ${activeTab === t ? 'bg-emerald-500 text-black font-bold' : 'bg-white/5 text-white/50'}`}
132→                >
133→                  {t.toUpperCase()}
134→                </button>
135→              ))}
136→            </div>
137→
138→            {/* Contenu de l'interface */}
139→            <div className="bg-white/5 border border-white/10 rounded-3xl p-8 min-h-[400px]">
140→              {activeTab === 'overview' && (
141→                <div className="text-center py-20">
142→                  <div className="inline-block relative">
143→                    <span className="text-8xl font-bold text-emerald-400">72</span>
144→                    <span className="text-2xl text-white/40">/100</span>
145→                  </div>
146→                  <h3 className="text-2xl font-bold mt-4">Score de Citabilité Global</h3>
147→                  <p className="text-white/50 mt-2">Votre site a une probabilité modérée d'être cité par les IA génératives.</p>
148→                </div>
149→              )}
150→              {activeTab === 'recommendations' && (
151→                <div className="grid md:grid-cols-2 gap-4">
152→                  <div className="p-6 bg-red-500/10 border border-red-500/20 rounded-2xl">
153→                    <h4 className="font-bold text-red-400 flex items-center gap-2"><AlertTriangle className="w-4 h-4"/> Critique</h4>
154→                    <p className="mt-2 text-sm text-white/70">Ajoutez des données structurées Schema.org FAQPage.</p>
155→                  </div>
156→                  <div className="p-6 bg-amber-500/10 border border-amber-500/20 rounded-2xl">
157→                    <h4 className="font-bold text-amber-400 flex items-center gap-2"><Lightbulb className="w-4 h-4"/> Amélioration</h4>
158→                    <p className="mt-2 text-sm text-white/70">Utilisez des listes à puces pour vos définitions clés.</p>
159→                  </div>
160→                </div>
161→              )}
162→            </div>
163→          </div>
164→        )}
165→      </main>
166→    </div>
167→  );
168→}

